#include <stdio.h>
int main() {
    int T; if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        long long P, M, V;
        scanf("%lld %lld %lld", &P, &M, &V);
        long long eff = M - (P - 1);
        long long ans = eff * V;
        printf("%lld\n", ans);
    }
    return 0;
}

